//! Comprehensive integration tests for the TemplateFlow API
//!
//! These tests require network connectivity and will download real data.
//! They are marked with #[ignore] by default to avoid running in CI.

use templateflow::{get_metadata, get_citations, templates, ls, get, get_async, get_multiple_async};
use std::collections::HashMap;
use tempfile::TempDir;

/// Helper to set up a temporary home directory for testing
fn setup_test_environment() -> TempDir {
    let temp_dir = TempDir::new().expect("Failed to create temp dir");
    std::env::set_var("TEMPLATEFLOW_HOME", temp_dir.path());
    temp_dir
}

#[test]
#[ignore] // Requires network access
fn test_templates_basic() {
    let _temp_dir = setup_test_environment();

    // Test listing all templates
    let all_templates = templates(None).expect("Failed to list templates");
    assert!(!all_templates.is_empty(), "Should have at least one template");

    // Verify some known templates exist
    assert!(all_templates.contains(&"MNI152NLin2009cAsym".to_string()));
    assert!(all_templates.contains(&"MNI152Lin".to_string()));
    assert!(all_templates.contains(&"fsaverage".to_string()));

    println!("Found {} templates", all_templates.len());
}

#[test]
#[ignore] // Requires network access
fn test_templates_with_query() {
    let _temp_dir = setup_test_environment();

    // Test filtering templates by resolution
    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());

    let filtered_templates = templates(Some(&query)).expect("Failed to query templates");
    assert!(!filtered_templates.is_empty(), "Should have templates with res=01");

    // All returned templates should have files with res=01
    for template in &filtered_templates {
        let mut template_query = HashMap::new();
        template_query.insert("res".to_string(), "01".to_string());
        let files = ls(template, Some(&template_query)).expect("Failed to list files");
        assert!(!files.is_empty(), "Template {} should have files with res=01", template);
    }
}

#[test]
#[ignore] // Requires network access
fn test_ls_basic() {
    let _temp_dir = setup_test_environment();

    // Test listing all files for a well-known template
    let files = ls("MNI152NLin2009cAsym", None).expect("Failed to list files");
    assert!(!files.is_empty(), "MNI152NLin2009cAsym should have files");

    // Verify file paths are properly formatted
    for file in &files {
        let path_str = file.to_string_lossy();
        assert!(path_str.starts_with("tpl-MNI152NLin2009cAsym/"));
        assert!(path_str.contains("tpl-MNI152NLin2009cAsym"));
    }
}

#[test]
#[ignore] // Requires network access
fn test_ls_with_queries() {
    let _temp_dir = setup_test_environment();

    // Test various query combinations
    let test_cases = vec![
        // Single entity queries
        (vec![("suffix", "T1w")], "suffix=T1w"),
        (vec![("res", "01")], "res=01"),
        (vec![("desc", "brain")], "desc=brain"),

        // Multiple entity queries
        (vec![("res", "01"), ("suffix", "T1w")], "res=01,suffix=T1w"),
        (vec![("suffix", "mask"), ("desc", "brain")], "suffix=mask,desc=brain"),
    ];

    for (query_params, description) in test_cases {
        let mut query = HashMap::new();
        for (key, value) in query_params {
            query.insert(key.to_string(), value.to_string());
        }

        match ls("MNI152NLin2009cAsym", Some(&query)) {
            Ok(files) => {
                println!("Query {} returned {} files", description, files.len());
                // Verify that returned files match the query
                for file in &files {
                    let path_str = file.to_string_lossy();
                    for (key, value) in &query {
                        if key == "suffix" {
                            assert!(path_str.contains(&format!("_{}.nii", value)) || 
                                    path_str.contains(&format!("_{}.json", value)),
                                    "File {} should match suffix={}", path_str, value);
                        } else if key == "res" {
                            assert!(path_str.contains(&format!("_res-{}", value)),
                                    "File {} should match res={}", path_str, value);
                        } else if key == "desc" {
                            assert!(path_str.contains(&format!("_desc-{}", value)),
                                    "File {} should match desc={}", path_str, value);
                        }
                    }
                }
            }
            Err(_) => {
                println!("Query {} returned no matches (this is OK)", description);
            }
        }
    }
}

#[test]
#[ignore] // Requires network access
fn test_ls_nonexistent_template() {
    let _temp_dir = setup_test_environment();

    // Test with a non-existent template
    let result = ls("NonExistentTemplate123", None);
    assert!(result.is_err(), "Should fail for non-existent template");
}

#[test]
#[ignore] // Requires network access
fn test_get_metadata() {
    let _temp_dir = setup_test_environment();

    // Test getting metadata for various templates
    let test_templates = vec![
        ("MNI152NLin2009cAsym", "ICBM 152 Nonlinear Asymmetrical"),
        ("MNI152Lin", "ICBM 2009c Nonlinear Symmetric"),
        ("fsaverage", "fsaverage"),
    ];

    for (template, expected_name_part) in test_templates {
        match get_metadata(template) {
            Ok(metadata) => {
                assert!(metadata.name.contains(expected_name_part) || 
                        metadata.name == expected_name_part,
                        "Template {} metadata name '{}' should contain '{}'", 
                        template, metadata.name, expected_name_part);
                assert!(!metadata.authors.is_empty(), 
                        "Template {} should have authors", template);
            }
            Err(e) => {
                // Some templates might not have metadata in the skeleton
                println!("Warning: Failed to get metadata for {}: {}", template, e);
            }
        }
    }
}

#[test]
#[ignore] // Requires network access
fn test_get_citations() {
    let _temp_dir = setup_test_environment();

    // Test getting citations in different formats
    match get_citations("MNI152NLin2009cAsym", false) {
        Ok(citations) => {
            assert!(!citations.is_empty(), "Should have at least one citation");
            for citation in &citations {
                assert!(!citation.is_empty(), "Citation should not be empty");
            }
        }
        Err(e) => {
            println!("Warning: Failed to get citations: {}", e);
        }
    }

    // Test BibTeX format
    match get_citations("MNI152NLin2009cAsym", true) {
        Ok(citations) => {
            assert!(!citations.is_empty(), "Should have at least one BibTeX citation");
            for citation in &citations {
                assert!(citation.starts_with("@misc{"), "BibTeX citation should start with @misc{");
                assert!(citation.contains("title ="), "BibTeX citation should have title field");
            }
        }
        Err(e) => {
            println!("Warning: Failed to get BibTeX citations: {}", e);
        }
    }
}

#[test]
#[ignore] // Requires network access and downloads files
fn test_get_basic() {
    let _temp_dir = setup_test_environment();

    // Find a small file to download for testing
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "T1w".to_string());
    query.insert("res".to_string(), "02".to_string()); // Lower resolution = smaller file

    // First, check what files are available
    match ls("MNI152NLin2009cAsym", Some(&query)) {
        Ok(available_files) => {
            if !available_files.is_empty() {
                // Download the files
                let downloaded = get("MNI152NLin2009cAsym", Some(&query))
                    .expect("Failed to download files");

                assert_eq!(downloaded.len(), available_files.len(), 
                           "Should download all matching files");

                // Verify all files exist
                for file in &downloaded {
                    assert!(file.exists(), "Downloaded file should exist: {:?}", file);
                    assert!(file.is_file(), "Downloaded path should be a file: {:?}", file);
                }

                // Test that re-downloading uses cache (should be fast)
                let start = std::time::Instant::now();
                let cached = get("MNI152NLin2009cAsym", Some(&query))
                    .expect("Failed to get cached files");
                let duration = start.elapsed();

                assert_eq!(cached.len(), downloaded.len(), 
                           "Cached result should have same number of files");
                assert!(duration.as_secs() < 1, 
                        "Cached retrieval should be fast (took {:?})", duration);
            }
        }
        Err(_) => {
            println!("No files matched the test query, trying simpler query");
            // Try without resolution constraint
            let mut simple_query = HashMap::new();
            simple_query.insert("suffix".to_string(), "T1w".to_string());

            if let Ok(files) = ls("MNI152NLin2009cAsym", Some(&simple_query)) {
                if !files.is_empty() {
                    // Just download the first file to test
                    let downloaded = get("MNI152NLin2009cAsym", Some(&simple_query))
                        .expect("Failed to download files");
                    assert!(!downloaded.is_empty(), "Should download at least one file");
                    assert!(downloaded[0].exists(), "First downloaded file should exist");
                }
            }
        }
    }
}

