#[test]
#[ignore] // Requires network access
fn test_cache_behavior() {
    let temp_dir = setup_test_environment();

    // Download a file
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "T1w".to_string());
    query.insert("res".to_string(), "02".to_string());

    if let Ok(files) = ls("MNI152NLin2009cAsym", Some(&query)) {
        if !files.is_empty() {
            // First download
            let downloaded1 = get("MNI152NLin2009cAsym", Some(&query))
                .expect("Failed to download files");

            // Verify files are in cache
            for file in &downloaded1 {
                assert!(file.exists());
                assert!(file.starts_with(temp_dir.path()));
            }

            // Delete one file to test re-download
            std::fs::remove_file(&downloaded1[0]).expect("Failed to remove file");
            assert!(!downloaded1[0].exists());

            // Re-download should restore the file
            let downloaded2 = get("MNI152NLin2009cAsym", Some(&query))
                .expect("Failed to re-download files");

            assert_eq!(downloaded1.len(), downloaded2.len());
            assert!(downloaded2[0].exists(), "File should be re-downloaded");
        }
    }
}

