//! CLI integration tests for TemplateFlow
//!
//! These tests verify the command-line interface functionality.

use assert_cmd::Command;
use predicates::prelude::*;
use tempfile::TempDir;
use std::fs;

/// Helper to create a command with test environment
fn templateflow_cmd() -> Command {
    let mut cmd = Command::cargo_bin("templateflow").unwrap();

    // Create a temporary home directory for each test
    let temp_dir = TempDir::new().unwrap();
    cmd.env("TEMPLATEFLOW_HOME", temp_dir.path());

    // Keep the temp dir alive by leaking it (OK for tests)
    std::mem::forget(temp_dir);

    cmd
}

#[test]
fn test_cli_help() {
    // Test main help
    templateflow_cmd()
        .arg("--help")
        .assert()
        .success()
        .stdout(predicate::str::contains("TemplateFlow"))
        .stdout(predicate::str::contains("USAGE"))
        .stdout(predicate::str::contains("Commands:"));

    // Test short help flag
    templateflow_cmd()
        .arg("-h")
        .assert()
        .success()
        .stdout(predicate::str::contains("TemplateFlow"));
}

